        led.set_high().unwrap();
        cortex_m::asm::delay(cp.SYST.main_count_down_hz(8_000_000));
        led.set_low().unwrap();
        cortex_m::asm::delay(cp.SYST.main_count_down_hz(8_000_000));
    }
}
